import { MatchedValue, Pattern } from './types/Pattern';
import * as P from './patterns';
import { matchPattern } from './internals/helpers';

/**
 * `isMatching` takes pattern and returns a **type guard** function, cheching if a value matches this pattern.
 *
 * [Read  documentation for `isMatching` on GitHub](https://github.com/gvergnaud/ts-pattern#ismatching)
 *
 * @example
 *  const hasName = isMatching({ name: P.string })
 *
 *  declare let input: unknown
 *
 *  if (hasName(input)) {
 *    // `input` inferred as { name: string }
 *    return input.name
 *  }
 */
export function isMatching<const p extends Pattern<unknown>>(
  pattern: p
): (value: unknown) => value is P.infer<p>;
/**
 * `isMatching` takes pattern and a value and checks if the value matches this pattern.
 *
 * [Read  documentation for `isMatching` on GitHub](https://github.com/gvergnaud/ts-pattern#ismatching)
 *
 * @example
 *  declare let input: unknown
 *
 *  if (isMatching({ name: P.string }, input)) {
 *    // `input` inferred as { name: string }
 *    return input.name
 *  }
 */
export function isMatching<const T, const P extends P.Pattern<NoInfer<T>>>(
  pattern: P,
  value: T
): value is P.infer<P>;

export function isMatching<const p extends Pattern<any>>(
  ...args: [pattern: p, value?: any]
): boolean | ((vale: any) => boolean) {
  if (args.length === 1) {
    const [pattern] = args;
    return (value: any): value is MatchedValue<any, P.infer<p>> =>
      matchPattern(pattern, value, () => {});
  }
  if (args.length === 2) {
    const [pattern, value] = args;
    return matchPattern(pattern, value, () => {});
  }

  throw new Error(
    `isMatching wasn't given the right number of arguments: expected 1 or 2, received ${args.length}.`
  );
}

import type * as symbols from '../internals/symbols';
import { MergeUnion, Primitives, WithDefault } from './helpers';
import { None, Some, SelectionType } from './FindSelected';
import { matcher } from '../patterns';
import { ExtractPreciseValue } from './ExtractPreciseValue';

export type MatcherType =
  | 'not'
  | 'optional'
  | 'or'
  | 'and'
  | 'array'
  | 'map'
  | 'set'
  | 'select'
  | 'default'
  | 'custom';

// We use a separate MatcherProtocol type to preserves
// the type level information (selections and excluded) used
// only for inference.
export type MatcherProtocol<
  input,
  narrowed,
  // Type of what this pattern selected from the input
  matcherType extends MatcherType,
  selections extends SelectionType,
  // Type to exclude from the input union because
  // it has been fully matched by this pattern
  excluded
> = {
  match: <I>(value: I | input) => MatchResult;
  getSelectionKeys?: () => string[];
  matcherType?: matcherType;
};

export type MatchResult = {
  matched: boolean;
  selections?: Record<string, any>;
};

/**
 * A `Matcher` is an object implementing the match
 * protocol. It must define a `symbols.matcher` property
 * which returns an object with a `match()` method, taking
 * the input value and returning whether the pattern matches
 * or not, along with optional selections.
 */
export interface Matcher<
  input,
  narrowed,
  // Type of what this pattern selected from the input
  matcherType extends MatcherType = 'default',
  selections extends SelectionType = None,
  // Type to exclude from the input union because
  // it has been fully matched by this pattern
  excluded = narrowed
> {
  [matcher](): MatcherProtocol<
    input,
    narrowed,
    matcherType,
    selections,
    excluded
  >;
  // only used for array matchers
  [symbols.isVariadic]?: boolean;
}

type PatternMatcher<input> = Matcher<input, unknown, any, any>;

// We fall back to `a` if we weren't able to extract anything more precise
export type MatchedValue<a, invpattern> = WithDefault<
  ExtractPreciseValue<a, invpattern>,
  a
>;

export type AnyMatcher = Matcher<any, any, any, any, any>;

type UnknownMatcher = PatternMatcher<unknown>;

export type CustomP<input, pattern, narrowedOrFn> = Matcher<
  input,
  pattern,
  //  👆
  // for the input type to be instantiated correctly
  // on subpatterns, it has to be passed through.
  'custom',
  None,
  narrowedOrFn
>;

export type ArrayP<input, p> = Matcher<input, p, 'array'>;

export type OptionalP<input, p> = Matcher<input, p, 'optional'>;

export type MapP<input, pkey, pvalue> = Matcher<input, [pkey, pvalue], 'map'>;

export type SetP<input, p> = Matcher<input, p, 'set'>;

export type AndP<input, ps> = Matcher<input, ps, 'and'>;

export type OrP<input, ps> = Matcher<input, ps, 'or'>;

export type NotP<input, p> = Matcher<input, p, 'not'>;

export type GuardP<input, narrowed> = Matcher<input, narrowed>;

export type GuardExcludeP<input, narrowed, excluded> = Matcher<
  input,
  narrowed,
  'default',
  None,
  excluded
>;

export type SelectP<
  key extends string,
  input = unknown,
  p = Matcher<unknown, unknown>
> = Matcher<input, p, 'select', Some<key>>;

export type AnonymousSelectP = SelectP<symbols.anonymousSelectKey>;

export interface Override<a> {
  [symbols.override]: a;
}

export type UnknownPattern =
  | readonly []
  | readonly [unknown, ...unknown[]]
  | readonly [...unknown[], unknown]
  | { readonly [k: string]: unknown }
  | Primitives
  | UnknownMatcher;

/**
 * `Pattern<a>` is the generic type for patterns matching a value of type `a`. A pattern can be any (nested) javascript value.
 *
 * They can also be wildcards, like `P._`, `P.string`, `P.number`,
 * or other matchers, like `P.when(predicate)`, `P.not(pattern)`, etc.
 *
 * [Read the documentation for `P.Pattern` on GitHub](https://github.com/gvergnaud/ts-pattern#patterns)
 *
 * @example
 * const pattern: P.Pattern<User> = { name: P.string }
 */
export type Pattern<a = unknown> = unknown extends a
  ? UnknownPattern
  : KnownPattern<a>;

type KnownPattern<a> = KnownPatternInternal<a>;

type KnownPatternInternal<
  a,
  objs = Exclude<a, Primitives | Map<any, any> | Set<any> | readonly any[]>,
  arrays = Extract<a, readonly any[]>,
  primitives = Extract<a, Primitives>
> =
  | primitives
  | PatternMatcher<a>
  | ([objs] extends [never] ? never : ObjectPattern<Readonly<MergeUnion<objs>>>)
  | ([arrays] extends [never] ? never : ArrayPattern<arrays>);

type ObjectPattern<a> =
  | {
      readonly [k in keyof a]?: Pattern<a[k]>;
    }
  | never;

type ArrayPattern<a> = a extends readonly (infer i)[]
  ? a extends readonly [any, ...any]
    ? { readonly [index in keyof a]: Pattern<a[index]> }
    :
        | readonly []
        | readonly [Pattern<i>, ...Pattern<i>[]]
        | readonly [...Pattern<i>[], Pattern<i>]
  : never;

// These aliases could be inferred, but lead to nicer display names in IDEs.
export type AnyPattern = Chainable<GuardP<unknown, unknown>, never>;
export type StringPattern = StringChainable<GuardP<unknown, string>, never>;
export type NumberPattern = NumberChainable<GuardP<unknown, number>, never>;
export type BooleanPattern = Chainable<GuardP<unknown, boolean>, never>;
export type BigIntPattern = BigIntChainable<GuardP<unknown, bigint>, never>;
export type SymbolPattern = Chainable<GuardP<unknown, symbol>, never>;
export type NullishPattern = Chainable<
  GuardP<unknown, null | undefined>,
  never
>;

export type NonNullablePattern = Chainable<GuardP<unknown, {}>, never>;

type MergeGuards<input, guard1, guard2> = [guard1, guard2] extends [
  GuardExcludeP<any, infer narrowed1, infer excluded1>,
  GuardExcludeP<any, infer narrowed2, infer excluded2>
]
  ? GuardExcludeP<input, narrowed1 & narrowed2, excluded1 & excluded2>
  : never;

export type Chainable<p, omitted extends string = never> = p &
  Omit<
    {
      /**
       * `.optional()` returns a pattern which matches if the
       * key is undefined or if it is defined and the previous pattern matches its value.
       *
       * [Read the documentation for `P.optional` on GitHub](https://github.com/gvergnaud/ts-pattern#poptional-patterns)
       *
       * @example
       *  match(value)
       *   .with({ greeting: P.string.optional() }, () => 'will match { greeting?: string}')
       */
      optional<input>(): Chainable<OptionalP<input, p>, omitted | 'optional'>;
      /**
       * `pattern.and(pattern)` returns a pattern that matches
       * if the previous pattern and the next one match the input.
       *
       * [Read the documentation for `P.intersection` on GitHub](https://github.com/gvergnaud/ts-pattern#pintersection-patterns)
       *
       * @example
       *  match(value)
       *   .with(
       *     P.string.and(P.when(isUsername)),
       *     (username) => '...'
       *   )
       */
      and<input, p2 extends Pattern<input>>(
        pattern: p2
      ): Chainable<AndP<input, [p, p2]>, omitted>;
      /**
       * `pattern.or(pattern)` returns a pattern that matches
       * if **either** the previous pattern or the next one match the input.
       *
       * [Read the documentation for `P.union` on GitHub](https://github.com/gvergnaud/ts-pattern#punion-patterns)
       *
       * @example
       *  match(value)
       *   .with(
       *     { value: P.string.or(P.number) },
       *     ({ value }) => 'value: number | string'
       *   )
       */
      or<input, p2 extends Pattern<input>>(
        pattern: p2
      ): Chainable<OrP<input, [p, p2]>, omitted>;
      /**
       * `P.select()` will inject this property into the handler function's arguments.
       *
       * [Read the documentation for `P.select` on GitHub](https://github.com/gvergnaud/ts-pattern#pselect-patterns)
       *
       * @example
       *  match<{ age: number }>(value)
       *   .with({ age: P.string.select() }, (age) => 'age: number')
       */
      select<input>(): Chainable<
        SelectP<symbols.anonymousSelectKey, input, p>,
        omitted | 'select' | 'or' | 'and'
      >;
      select<input, k extends string>(
        key: k
      ): Chainable<SelectP<k, input, p>, omitted | 'select' | 'or' | 'and'>;
    },
    omitted
  >;

export type StringChainable<
  p extends Matcher<any, any, any, any, any>,
  omitted extends string = never
> = Chainable<p, omitted> &
  Omit<
    {
      /**
       * `P.string.startsWith(start)` is a pattern, matching **strings** starting with `start`.
       *
       * [Read the documentation for `P.string.startsWith` on GitHub](https://github.com/gvergnaud/ts-pattern#pstringstartsWith)
       *
       * @example
       *  match(value)
       *   .with(P.string.startsWith('A'), () => 'value starts with an A')
       */
      startsWith<input, const start extends string>(
        start: start
      ): StringChainable<
        MergeGuards<input, p, GuardP<unknown, `${start}${string}`>>,
        omitted | 'startsWith'
      >;
      /**
       * `P.string.endsWith(end)` is a pattern, matching **strings** ending with `end`.
       *
       * [Read the documentation for `P.string.endsWith` on GitHub](https://github.com/gvergnaud/ts-pattern#pstringendsWith)
       *
       * @example
       *  match(value)
       *   .with(P.string.endsWith('!'), () => 'value ends with an !')
       */
      endsWith<input, const end extends string>(
        end: end
      ): StringChainable<

export type ValueOf<a> = a extends readonly any[] ? a[number] : a[keyof a];

export type Values<a extends object> = UnionToTuple<ValueOf<a>>;

/**
 * ### LeastUpperBound
 * An interesting one. A type taking two imbricated sets and returning the
 * smallest one.
 * We need that because sometimes the pattern's inferred type holds more
 * information than the value on which we are matching (if the value is any
 * or unknown for instance).
 */

export type LeastUpperBound<a, b> = b extends a ? b : a extends b ? a : never;

export type Contains<a, b> = a extends any
  ? 'exclude' extends {
      [k in keyof a]-?: Equal<a[k], b> extends true ? 'exclude' : 'include';
    }[keyof a]
    ? true
    : false
  : never;

// from https://stackoverflow.com/questions/50374908/transform-union-type-to-intersection-type/50375286#50375286
export type UnionToIntersection<union> = (
  union extends any ? (k: union) => void : never
) extends (k: infer intersection) => void
  ? intersection
  : never;

export type IsUnion<a> = [a] extends [UnionToIntersection<a>] ? false : true;

export type UnionToTuple<
  union,
  output extends any[] = []
> = UnionToIntersection<
  union extends any ? (t: union) => union : never
> extends (_: any) => infer elem
  ? UnionToTuple<Exclude<union, elem>, [elem, ...output]>
  : output;

export type Flatten<
  xs extends readonly any[],
  output extends any[] = []
> = xs extends readonly [infer head, ...infer tail]
  ? Flatten<tail, [...output, ...Extract<head, readonly any[]>]>
  : output;

export type Equal<a, b> = (<T>() => T extends a ? 1 : 2) extends <
  T
>() => T extends b ? 1 : 2
  ? true
  : false;

export type Expect<a extends true> = a;

export type IsAny<a> = 0 extends 1 & a ? true : false;

export type IsNever<T> = [T] extends [never] ? true : false;

export type Length<it extends readonly any[]> = it['length'];

export type Iterator<
  n extends number,
  it extends any[] = []
> = it['length'] extends n ? it : Iterator<n, [any, ...it]>;

export type Next<it extends any[]> = [any, ...it];
export type Prev<it extends any[]> = it extends readonly [any, ...infer tail]
  ? tail
  : [];

export type Take<
  xs extends readonly any[],
  it extends any[],
  output extends any[] = []
> = Length<it> extends 0
  ? output
  : xs extends readonly [infer head, ...infer tail]
  ? Take<tail, Prev<it>, [...output, head]>
  : output;

export type Drop<
  xs extends readonly any[],
  n extends any[]
> = Length<n> extends 0
  ? xs
  : xs extends readonly [any, ...infer tail]
  ? Drop<tail, Prev<n>>
  : [];

export type UpdateAt<
  tail extends readonly any[],
  n extends any[],
  value,
  inits extends readonly any[] = []
> = Length<n> extends 0
  ? tail extends readonly [any, ...infer tail]
    ? [...inits, value, ...tail]
    : inits
  : tail extends readonly [infer head, ...infer tail]
  ? UpdateAt<tail, Prev<n>, value, [...inits, head]>
  : inits;

export type BuiltInObjects =
  | Function
  | Date
  | RegExp
  | Generator
  | { readonly [Symbol.toStringTag]: string }
  | any[];

export type IsPlainObject<o, excludeUnion = BuiltInObjects> = o extends object
  ? // to excluded branded string types,
    // like `string & { __brand: "id" }`
    // and built-in objects
    o extends string | excludeUnion
    ? false
    : true
  : false;

export type Compute<a extends any> = a extends BuiltInObjects
  ? a
  : { [k in keyof a]: a[k] };

export type IntersectObjects<a> = (
  a extends any ? keyof a : never
) extends infer allKeys
  ? {
      [k in Extract<allKeys, PropertyKey>]: a extends any
        ? k extends keyof a
          ? a[k]
          : never
        : never;
    }
  : never;

export type WithDefault<a, def> = [a] extends [never] ? def : a;

export type IsLiteral<a> = [a] extends [null | undefined]
  ? true
  : [a] extends [string]
  ? string extends a
    ? false
    : true
  : [a] extends [number]
  ? number extends a
    ? false
    : true
  : [a] extends [boolean]
  ? boolean extends a
    ? false
    : true
  : [a] extends [symbol]
  ? symbol extends a
    ? false
    : true
  : [a] extends [bigint]
  ? bigint extends a
    ? false
    : true
  : false;

export type Primitives =
  | number
  | boolean
  | string
  | undefined
  | null
  | symbol
  | bigint;

export type NonLiteralPrimitive = Exclude<Primitives, undefined | null>;

export type TupleKeys = '0' | '1' | '2' | '3' | '4';

export type Union<a, b> = [b] extends [a] ? a : [a] extends [b] ? b : a | b;

/**
 * GuardValue returns the value guarded by a type guard function.
 */
export type GuardValue<fn> = fn extends (value: any) => value is infer b
  ? b
  : fn extends (value: infer a) => unknown
  ? a
  : never;

export type GuardFunction<input, narrowed> =
  | ((value: input) => value is Extract<narrowed, input>)
  | ((value: input) => boolean);

export type Some<bools extends boolean[]> = true extends bools[number]
  ? true
  : false;

export type All<bools extends boolean[]> = bools[number] extends true
  ? true
  : false;

export type Extends<a, b> = [a] extends [b] ? true : false;

export type Not<a extends boolean> = a extends true ? false : true;

type AllKeys<a> = a extends any ? keyof a : never;

// Merge unions of objects into a single object with unions of keys
export type MergeUnion<a> =
  | {
      [k in AllKeys<a>]: a extends any
        ? k extends keyof a
          ? a[k]
          : never
        : never;
    }
  | never;

export type IsFixedSizeTuple<a extends readonly any[]> = IsLiteral<Length<a>>;

// is it a fixed size or a variadic tuple
export type IsTuple<a> = a extends
  | readonly []
  | readonly [any, ...any]
  | readonly [...any, any]
  ? true
  : false;

export type IsStrictArray<a extends readonly any[]> = Not<IsTuple<a>>;

export type IsReadonlyArray<a> = a extends readonly any[]
  ? a extends any[] // mutable array
    ? false
    : true
  : false;

export type MaybeAddReadonly<
  a,
  shouldAdd extends boolean
> = shouldAdd extends true ? Readonly<a> : a;

export type MapKey<T> = T extends Map<infer K, any> ? K : never;

export type MapValue<T> = T extends Map<any, infer V> ? V : never;

export type SetValue<T> = T extends Set<infer V> ? V : never;

export type ReadonlyArrayValue<T> = T extends ReadonlyArray<infer V>
  ? V
  : never;

export type ExtractPlainObject<T> = T extends any
  ? IsPlainObject<T> extends true
    ? T
    : never
  : never;

export type GetKey<O, K> = O extends any
  ? K extends keyof O
    ? O[K]
    : never
  : never;

export interface Fn {
  input: unknown;
  output: unknown;
}

export type Call<fn extends Fn, input> = (fn & {
  input: input;
})['output'];

